import{c as e,Q as a,j as l,m as s}from"./chunks/framework.CQqJojvj.js";const h=JSON.parse('{"title":"03 - JVM","description":"","frontmatter":{},"headers":[],"relativePath":"bagu/03-jvm.md","filePath":"bagu/03-jvm.md","lastUpdated":null}'),n={name:"bagu/03-jvm.md"};function i(d,t,r,p,o,c){return a(),l("div",null,[...t[0]||(t[0]=[s(`<h1 id="_03-jvm" tabindex="-1">03 - JVM <a class="header-anchor" href="#_03-jvm" aria-label="Permalink to &quot;03 - JVM&quot;">​</a></h1><blockquote><p>JVM 是性能调优和问题排查的基础。内存模型、垃圾回收、类加载机制是高频考点。</p></blockquote><hr><h2 id="_1-jvm-内存结构-运行时数据区" tabindex="-1">1. JVM 内存结构（运行时数据区） <a class="header-anchor" href="#_1-jvm-内存结构-运行时数据区" aria-label="Permalink to &quot;1. JVM 内存结构（运行时数据区）&quot;">​</a></h2><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌─────────────────────────────────────────┐</span></span>
<span class="line"><span>│              线程共享区域                 │</span></span>
<span class="line"><span>│  ┌─────────────┐  ┌───────────────────┐ │</span></span>
<span class="line"><span>│  │   堆 (Heap)  │  │ 方法区 (Metaspace) │ │</span></span>
<span class="line"><span>│  │  对象/数组   │  │ 类信息/常量/静态变量│ │</span></span>
<span class="line"><span>│  └─────────────┘  └───────────────────┘ │</span></span>
<span class="line"><span>├─────────────────────────────────────────┤</span></span>
<span class="line"><span>│              线程私有区域                 │</span></span>
<span class="line"><span>│  ┌────────┐ ┌────────┐ ┌──────────────┐ │</span></span>
<span class="line"><span>│  │程序计数器│ │虚拟机栈 │ │  本地方法栈   │ │</span></span>
<span class="line"><span>│  │ PC Reg  │ │VM Stack│ │ Native Stack│ │</span></span>
<span class="line"><span>│  └────────┘ └────────┘ └──────────────┘ │</span></span>
<span class="line"><span>└─────────────────────────────────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><h3 id="堆-heap" tabindex="-1">堆（Heap） <a class="header-anchor" href="#堆-heap" aria-label="Permalink to &quot;堆（Heap）&quot;">​</a></h3><p><strong>分代模型（JDK 8）：</strong></p><ul><li><strong>新生代（Young）：</strong> 默认占堆 1/3，包含 Eden + S0 + S1（比例 8:1:1）</li><li><strong>老年代（Old）：</strong> 默认占堆 2/3</li></ul><p><strong>对象分配流程：</strong></p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>new → Eden（不够触发 Minor GC）→ Survivor（来回拷贝，年龄+1）</span></span>
<span class="line"><span>→ 年龄达到阈值（默认15）→ 老年代 → Full GC 回收</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p><strong>大对象直接进老年代：</strong> 超过 <code>-XX:PretenureSizeThreshold</code> 的大对象直接在老年代分配，避免在 Eden/Survivor 之间来回复制。</p><h3 id="虚拟机栈" tabindex="-1">虚拟机栈 <a class="header-anchor" href="#虚拟机栈" aria-label="Permalink to &quot;虚拟机栈&quot;">​</a></h3><p>每个线程创建时分配，包含多个<strong>栈帧</strong>（Stack Frame），每个方法调用对应一个栈帧：</p><table tabindex="0"><thead><tr><th style="text-align:left;">组成部分</th><th style="text-align:left;">说明</th></tr></thead><tbody><tr><td style="text-align:left;">局部变量表</td><td style="text-align:left;">存储方法参数和局部变量（基本类型+引用）</td></tr><tr><td style="text-align:left;">操作数栈</td><td style="text-align:left;">字节码指令操作的临时数据</td></tr><tr><td style="text-align:left;">动态链接</td><td style="text-align:left;">指向运行时常量池中该方法的引用</td></tr><tr><td style="text-align:left;">返回地址</td><td style="text-align:left;">方法出口</td></tr></tbody></table><p><strong>StackOverflowError vs OutOfMemoryError：</strong></p><ul><li>线程请求的栈深度 &gt; JVM 允许的最大深度 → <code>StackOverflowError</code></li><li>创建过多栈帧（如递归过深）或线程数过多，内存不够创建新栈 → <code>OutOfMemoryError</code></li></ul><h3 id="方法区-metaspace" tabindex="-1">方法区（Metaspace） <a class="header-anchor" href="#方法区-metaspace" aria-label="Permalink to &quot;方法区（Metaspace）&quot;">​</a></h3><p>JDK 8 用 Metaspace（本地内存）替代永久代（PermGen）：</p><table tabindex="0"><thead><tr><th style="text-align:left;">特性</th><th style="text-align:left;">PermGen (JDK 7)</th><th style="text-align:left;">Metaspace (JDK 8+)</th></tr></thead><tbody><tr><td style="text-align:left;">存储位置</td><td style="text-align:left;">JVM 堆内</td><td style="text-align:left;">本地内存（Native Memory）</td></tr><tr><td style="text-align:left;">大小限制</td><td style="text-align:left;"><code>-XX:MaxPermSize</code></td><td style="text-align:left;"><code>-XX:MaxMetaspaceSize</code>（默认无限制）</td></tr><tr><td style="text-align:left;">溢出异常</td><td style="text-align:left;"><code>java.lang.OutOfMemoryError: PermGen space</code></td><td style="text-align:left;"><code>java.lang.OutOfMemoryError: Metaspace</code></td></tr></tbody></table><p>存放内容：类信息、运行时常量池、静态变量、JIT 编译后的代码缓存。</p><hr><h2 id="_2-对象的创建与访问" tabindex="-1">2. 对象的创建与访问 <a class="header-anchor" href="#_2-对象的创建与访问" aria-label="Permalink to &quot;2. 对象的创建与访问&quot;">​</a></h2><h3 id="创建对象的过程" tabindex="-1">创建对象的过程 <a class="header-anchor" href="#创建对象的过程" aria-label="Permalink to &quot;创建对象的过程&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 类加载检查（检查是否已被加载、解析、初始化）</span></span>
<span class="line"><span>2. 分配内存（指针碰撞 / 空闲列表，取决于 GC 是否有压缩）</span></span>
<span class="line"><span>3. 初始化零值（保证不赋初值就能使用）</span></span>
<span class="line"><span>4. 设置对象头（Mark Word + 类型指针）</span></span>
<span class="line"><span>5. 执行 &lt;init&gt; 方法（构造器 + 初始化块）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><h3 id="对象一定分配在堆里吗" tabindex="-1">对象一定分配在堆里吗？ <a class="header-anchor" href="#对象一定分配在堆里吗" aria-label="Permalink to &quot;对象一定分配在堆里吗？&quot;">​</a></h3><p>不一定。JIT 编译时，如果对象不会逃逸出方法，可以通过<strong>逃逸分析</strong>在<strong>栈上分配</strong>，减少 GC 压力。另外虚拟对象（标量替换）也可以直接拆分为基本类型在栈上分配。</p><h3 id="对象的内存布局" tabindex="-1">对象的内存布局 <a class="header-anchor" href="#对象的内存布局" aria-label="Permalink to &quot;对象的内存布局&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>┌───────────────┐</span></span>
<span class="line"><span>│   对象头       │ Mark Word (8B) + Klass Pointer (4B/8B)</span></span>
<span class="line"><span>├───────────────┤</span></span>
<span class="line"><span>│   实例数据     │ 字段（含父类字段）</span></span>
<span class="line"><span>├───────────────┤</span></span>
<span class="line"><span>│   对齐填充     │ 保证 8 字节对齐</span></span>
<span class="line"><span>└───────────────┘</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>Mark Word：</strong> 存储对象自身的运行时数据（HashCode、GC分代年龄、锁状态标志、线程持有的锁、偏向线程ID等），在 32/64 位 JVM 中分别为 32/64 bit。</p><hr><h2 id="_3-垃圾回收" tabindex="-1">3. 垃圾回收 <a class="header-anchor" href="#_3-垃圾回收" aria-label="Permalink to &quot;3. 垃圾回收&quot;">​</a></h2><h3 id="判断对象是否可回收" tabindex="-1">判断对象是否可回收 <a class="header-anchor" href="#判断对象是否可回收" aria-label="Permalink to &quot;判断对象是否可回收&quot;">​</a></h3><p><strong>根可达性分析（GC Roots）：</strong></p><p>从 GC Roots 对象出发，沿着引用链向下搜索，无法到达的对象判定为可回收。</p><p><strong>GC Roots 包括：</strong></p><ol><li>虚拟机栈中引用的对象（局部变量）</li><li>方法区中静态变量引用的对象</li><li>方法区中常量引用的对象</li><li>本地方法栈中 JNI 引用的对象</li><li>所有被同步锁（synchronized）持有的对象</li><li>Java 虚拟机内部的引用（基本数据类型的 Class 对象、常驻异常、类加载器等）</li></ol><h3 id="垃圾回收算法" tabindex="-1">垃圾回收算法 <a class="header-anchor" href="#垃圾回收算法" aria-label="Permalink to &quot;垃圾回收算法&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">算法</th><th style="text-align:left;">原理</th><th style="text-align:left;">优点</th><th style="text-align:left;">缺点</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>标记-清除</strong></td><td style="text-align:left;">标记存活对象，清除未标记的</td><td style="text-align:left;">简单</td><td style="text-align:left;">产生内存碎片</td></tr><tr><td style="text-align:left;"><strong>标记-复制</strong></td><td style="text-align:left;">将存活对象复制到另一块区域</td><td style="text-align:left;">无碎片，效率高</td><td style="text-align:left;">浪费一半空间</td></tr><tr><td style="text-align:left;"><strong>标记-整理</strong></td><td style="text-align:left;">标记后将存活对象移向一端</td><td style="text-align:left;">无碎片</td><td style="text-align:left;">移动对象开销大，STW</td></tr><tr><td style="text-align:left;"><strong>分代收集</strong></td><td style="text-align:left;">新生代用复制，老年代用标记-整理</td><td style="text-align:left;">兼顾效率和空间</td><td style="text-align:left;">实现复杂</td></tr></tbody></table><h3 id="垃圾回收器" tabindex="-1">垃圾回收器 <a class="header-anchor" href="#垃圾回收器" aria-label="Permalink to &quot;垃圾回收器&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">回收器</th><th style="text-align:left;">收集区域</th><th style="text-align:left;">算法</th><th style="text-align:left;">特点</th><th style="text-align:left;">适用场景</th></tr></thead><tbody><tr><td style="text-align:left;">Serial</td><td style="text-align:left;">新生代</td><td style="text-align:left;">复制</td><td style="text-align:left;">单线程，STW 长</td><td style="text-align:left;">客户端应用</td></tr><tr><td style="text-align:left;">ParNew</td><td style="text-align:left;">新生代</td><td style="text-align:left;">复制</td><td style="text-align:left;">多线程并行</td><td style="text-align:left;">CMS 搭档</td></tr><tr><td style="text-align:left;">Parallel Scavenge</td><td style="text-align:left;">新生代</td><td style="text-align:left;">复制</td><td style="text-align:left;">吞吐量优先</td><td style="text-align:left;">后台计算</td></tr><tr><td style="text-align:left;">Serial Old</td><td style="text-align:left;">老年代</td><td style="text-align:left;">标记-整理</td><td style="text-align:left;">单线程</td><td style="text-align:left;">客户端</td></tr><tr><td style="text-align:left;">CMS</td><td style="text-align:left;">老年代</td><td style="text-align:left;">标记-清除</td><td style="text-align:left;">低停顿目标</td><td style="text-align:left;">互联网应用</td></tr><tr><td style="text-align:left;">G1</td><td style="text-align:left;">全部</td><td style="text-align:left;">标记-整理+复制</td><td style="text-align:left;">可控停顿</td><td style="text-align:left;">大堆（&gt;4G）</td></tr><tr><td style="text-align:left;">ZGC</td><td style="text-align:left;">全部</td><td style="text-align:left;">标记-复制（染色指针）</td><td style="text-align:left;">亚毫秒停顿</td><td style="text-align:left;">低延迟，大堆</td></tr><tr><td style="text-align:left;">Shenandoah</td><td style="text-align:left;">全部</td><td style="text-align:left;">标记-复制</td><td style="text-align:left;">低停顿</td><td style="text-align:left;">大堆</td></tr></tbody></table><p><strong>CMS 的缺点：</strong></p><ol><li>并发阶段仍占用 CPU 资源</li><li>标记-清除算法会产生内存碎片</li><li>无法处理浮动垃圾（并发清理阶段新产生的垃圾）</li><li>JDK 14 已废弃，JDK 15 移除</li></ol><p><strong>G1 的特点：</strong></p><ul><li>将堆划分为大小相等的 Region（默认 2048 个）</li><li>每次回收价值最高的 Region（Garbage First）</li><li>通过 <code>-XX:MaxGCPauseMillis</code> 设定停顿目标</li><li>使用 Remembered Set 解决跨 Region 引用问题</li></ul><h3 id="三色标记法" tabindex="-1">三色标记法 <a class="header-anchor" href="#三色标记法" aria-label="Permalink to &quot;三色标记法&quot;">​</a></h3><p>CMS 和 G1 使用三色标记法进行并发标记：</p><ul><li><strong>白色：</strong> 未被访问（标记结束后白色对象被回收）</li><li><strong>灰色：</strong> 已访问但引用尚未扫描</li><li><strong>黑色：</strong> 已访问且引用已扫描</li></ul><p><strong>漏标问题（黑色对象引用了白色对象）：</strong></p><p>解决方式：</p><ul><li><strong>增量更新（CMS）：</strong> 黑色对象新增白色引用时，将黑色重新标记为灰色</li><li><strong>原始快照 SATB（G1）：</strong> 灰色对象删除白色引用时，记录该白色对象</li></ul><hr><h2 id="_4-类加载机制" tabindex="-1">4. 类加载机制 <a class="header-anchor" href="#_4-类加载机制" aria-label="Permalink to &quot;4. 类加载机制&quot;">​</a></h2><h3 id="类的生命周期" tabindex="-1">类的生命周期 <a class="header-anchor" href="#类的生命周期" aria-label="Permalink to &quot;类的生命周期&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>加载 → 验证 → 准备 → 解析 → 初始化 → 使用 → 卸载</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="双亲委派模型" tabindex="-1">双亲委派模型 <a class="header-anchor" href="#双亲委派模型" aria-label="Permalink to &quot;双亲委派模型&quot;">​</a></h3><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Bootstrap ClassLoader (加载核心类 rt.jar)</span></span>
<span class="line"><span>         ↑</span></span>
<span class="line"><span>Extension ClassLoader (加载扩展类 jre/lib/ext)</span></span>
<span class="line"><span>         ↑</span></span>
<span class="line"><span>Application ClassLoader (加载 classpath 下的类)</span></span>
<span class="line"><span>         ↑</span></span>
<span class="line"><span>自定义 ClassLoader</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p><strong>工作流程：</strong></p><ol><li>收到加载请求时，先委托父类加载器</li><li>父类无法加载时，子类才尝试加载</li></ol><p><strong>为什么需要双亲委派？</strong></p><ol><li>安全性 — 防止核心类（如 <code>java.lang.Object</code>）被篡改</li><li>避免重复加载 — 同一个类只被加载一次</li></ol><p><strong>如何打破双亲委派？</strong></p><p>重写 <code>findClass()</code> 方法而不是 <code>loadClass()</code> 方法。例如 Tomcat 为了支持多个 Web 应用隔离，使用自定义 ClassLoader 打破双亲委派。</p><hr><h2 id="_5-jvm-调优" tabindex="-1">5. JVM 调优 <a class="header-anchor" href="#_5-jvm-调优" aria-label="Permalink to &quot;5. JVM 调优&quot;">​</a></h2><h3 id="常用调优参数" tabindex="-1">常用调优参数 <a class="header-anchor" href="#常用调优参数" aria-label="Permalink to &quot;常用调优参数&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">参数</th><th style="text-align:left;">说明</th><th style="text-align:left;">示例</th></tr></thead><tbody><tr><td style="text-align:left;"><code>-Xms</code></td><td style="text-align:left;">初始堆大小</td><td style="text-align:left;"><code>-Xms2g</code></td></tr><tr><td style="text-align:left;"><code>-Xmx</code></td><td style="text-align:left;">最大堆大小</td><td style="text-align:left;"><code>-Xmx4g</code></td></tr><tr><td style="text-align:left;"><code>-Xmn</code></td><td style="text-align:left;">新生代大小</td><td style="text-align:left;"><code>-Xmn1g</code></td></tr><tr><td style="text-align:left;"><code>-XX:+UseG1GC</code></td><td style="text-align:left;">使用 G1 垃圾回收器</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><code>-XX:MaxGCPauseMillis</code></td><td style="text-align:left;">期望最大 GC 停顿</td><td style="text-align:left;"><code>-XX:MaxGCPauseMillis=200</code></td></tr><tr><td style="text-align:left;"><code>-XX:+PrintGCDetails</code></td><td style="text-align:left;">打印 GC 详细日志</td><td style="text-align:left;">—</td></tr><tr><td style="text-align:left;"><code>-XX:+HeapDumpOnOutOfMemoryError</code></td><td style="text-align:left;">OOM 时 Dump 堆</td><td style="text-align:left;">—</td></tr></tbody></table><h3 id="调优思路" tabindex="-1">调优思路 <a class="header-anchor" href="#调优思路" aria-label="Permalink to &quot;调优思路&quot;">​</a></h3><ol><li>先看 GC 日志，确定是 Minor GC 频繁还是 Full GC 频繁</li><li>Minor GC 频繁 → 调大新生代</li><li>Full GC 频繁 → 分析老年代增长原因（大对象、内存泄漏）</li><li>STW 过长 → 考虑换 GC 回收器（G1/ZGC）</li></ol><h3 id="常见-oom-场景" tabindex="-1">常见 OOM 场景 <a class="header-anchor" href="#常见-oom-场景" aria-label="Permalink to &quot;常见 OOM 场景&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">异常</th><th style="text-align:left;">原因</th></tr></thead><tbody><tr><td style="text-align:left;"><code>java.lang.OutOfMemoryError: Java heap space</code></td><td style="text-align:left;">堆内存不足</td></tr><tr><td style="text-align:left;"><code>java.lang.OutOfMemoryError: Metaspace</code></td><td style="text-align:left;">加载太多类</td></tr><tr><td style="text-align:left;"><code>java.lang.OutOfMemoryError: unable to create new native thread</code></td><td style="text-align:left;">线程数过多</td></tr><tr><td style="text-align:left;"><code>java.lang.StackOverflowError</code></td><td style="text-align:left;">栈溢出（递归过深）</td></tr></tbody></table>`,70)])])}const b=e(n,[["render",i]]);export{h as __pageData,b as default};
